if (!fs.existsSync(DATA_FILE)) {
  fs.writeFileSync(DATA_FILE, JSON.stringify(defaultData, null, 2), 'utf-8');
}

export function readData() {
  try {
    const raw = fs.readFileSync(DATA_FILE, 'utf-8');
    return JSON.parse(raw);
  } catch (error) {
    console.error("Error reading database file, resetting:", error);
    return defaultData;
  }
}

export function writeData(data) {
  try {
    fs.writeFileSync(DATA_FILE, JSON.stringify(data, null, 2), 'utf-8');
    return true;
  } catch (error) {
    console.error("Error writing to database file:", error);
    return false;
  }
}

export function getIncidents() {
  return readData().incidents;
}

export function saveIncident(incident) {
  const data = readData();
  const index = data.incidents.findIndex(inc => inc.id === incident.id);
  if (index >= 0) {
    data.incidents[index] = { ...data.incidents[index], ...incident };
  } else {
    data.incidents.unshift(incident);
  }
  writeData(data);
  return incident;
}

export function deleteIncident(id) {
  const data = readData();
  data.incidents = data.incidents.filter(inc => inc.id !== id);
  writeData(data);
  return true;
}

export function getTeams() {
  return readData().teams;
}

export function updateTeamStatus(id, type, status, location) {
  const data = readData();
  const list = data.teams[type];
  if (!list) return false;
  const team = list.find(t => t.id === id);
  if (team) {
    team.status = status;
    if (location) team.location = location;
    writeData(data);
    return team;
  }
  return false;
}

export function getAnnouncements() {
  return readData().announcements;
}

export function saveAnnouncement(announcement) {
  const data = readData();
  data.announcements.unshift(announcement);
  writeData(data);
  return announcement;
}

import https from 'https';
import dotenv from 'dotenv';

dotenv.config();

const apiKey = process.env.GEMINI_API_KEY;
const isSimulatorMode = !apiKey || apiKey === "YOUR_GEMINI_API_KEY";

if (isSimulatorMode) {
  console.log("No valid GEMINI_API_KEY found. Operating in local intelligent simulation mode.");
} else {
  console.log("Valid GEMINI_API_KEY found. Live Google Gemini API integrated.");
}

// ----------------------------------------------------
// HTTPS Request Wrapper for Gemini
// ----------------------------------------------------
function callGeminiAPI(systemInstruction, prompt, useJson = false) {
  return new Promise((resolve, reject) => {
    if (isSimulatorMode) {
      reject(new Error("Simulator mode active"));
      return;
    }

    const model = "gemini-2.5-flash";
    const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;

    const payload = {
      contents: [
        {
          role: 'user',
          parts: [{ text: prompt }]
        }
      ]
    };

    if (systemInstruction) {
      payload.systemInstruction = {
        parts: [{ text: systemInstruction }]
      };
    }

    if (useJson) {
      payload.generationConfig = {
        responseMimeType: "application/json"
      };
    }

    const requestData = JSON.stringify(payload);

    const options = {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(requestData)
      }
    };

    const req = https.request(url, options, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        if (res.statusCode >= 200 && res.statusCode < 300) {
          try {
            const parsed = JSON.parse(body);
            const textResponse = parsed.candidates?.[0]?.content?.parts?.[0]?.text;
            if (textResponse) {
              resolve(textResponse.trim());
            } else {
              reject(new Error("No text response in Gemini output structure"));
            }
          } catch (e) {
            reject(new Error("Failed to parse Gemini response: " + e.message));
          }
        } else {
          reject(new Error(`API Error ${res.statusCode}: ${body}`));
        }
      });
    });

    req.on('error', (e) => reject(e));
    req.write(requestData);
    req.end();
  });
}

